class NoteStore {
    constructor() {
        this.notes = new Map();
    }

    create(note) {
        this.notes.set(note.id, note);
        return note;
    }

    retrieve(id) {
        return this.notes.get(id) || null;
    }

    update(id, updatedNote) {
        if (!this.notes.has(id)) {
            return null;
        }
        this.notes.set(id, updatedNote);
        return updatedNote;
    }

    delete(id) {
        return this.notes.delete(id);
    }

    list(query, category) {
        const notesArray = Array.from(this.notes.values());
        return notesArray.filter(note => {
            const matchesCategory = category ? note.category === category : true;
            const matchesQuery = query ? (note.title.includes(query) || note.body.includes(query)) : true;
            return matchesCategory && matchesQuery;
        });
    }
}

module.exports = new NoteStore();

let currentId = 0;

function generateId() {
    currentId += 1;
    return currentId;
}

module.exports = generateId;

function validateNoteInput(req, res, next) {
    const { title } = req.body;
    if (typeof title !== 'string' || title.length > 200) {
        return res.status(400).json({ error: 'Invalid title. It must be a string and no more than 200 characters long.' });
    }
    next();
}

module.exports = validateNoteInput;

const express = require('express');
const noteStore = require('../models/noteStore');
const generateId = require('../utils/idGenerator');
const validateNoteInput = require('../middleware/validation');

const router = express.Router();

router.post('/notes', validateNoteInput, (req, res) => {
    const { title, body, category, tags } = req.body;
    const id = generateId();
    const note = { id, title, body, category, tags };
    noteStore.create(note);
    res.status(201).json(note);
});

router.get('/notes', (req, res) => {
    const { category, q } = req.query;
    const notes = noteStore.list(q, category);
    res.json(notes);
});

router.get('/notes/:id', (req, res) => {
    const { id } = req.params;
    const note = noteStore.retrieve(parseInt(id));
    if (!note) {
        return res.status(404).json({ error: 'Note not found' });
    }
    res.json(note);
});

router.put('/notes/:id', validateNoteInput, (req, res) => {
    const { title, body, category, tags } = req.body;
    const { id } = req.params;
    const updatedNote = { id: parseInt(id), title, body, category, tags };
    const result = noteStore.update(parseInt(id), updatedNote);
    if (!result) {
        return res.status(404).json({ error: 'Note not found' });
    }
    res.json(result);
});

router.delete('/notes/:id', (req, res) => {
    const { id } = req.params;
    const result = noteStore.delete(parseInt(id));
    if (!result) {
        return res.status(404).json({ error: 'Note not found' });
    }
    res.status(204).send();
});

module.exports = router;

const express = require('express');
const notesRoutes = require('./routes/notes');

const app = express();

app.use(express.json());
app.use('', notesRoutes);

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});
